(1941, 'assessment_introduction', 11, '{\"section_id\": \"introduction\", \"is_complete\": false, \"last_updated\": \"2025-08-29T08:57:55.515Z\", \"response_date\": \"2025-08-29T08:57:55.515Z\", \"questionnaire_id\": \"business-assessment-v1\", \"question_responses\": [{\"value\": \"Sewing and tailoring for individual. Want to upgrade to do bulk sewing. Focusing on uniforms and PPE and scrubs.\", \"question_id\": \"intro_business_description\", \"response_date\": \"2025-08-29T08:57:55.515Z\"}, {\"value\": \"I want to make money, and this is my passion. Current state of the business. Currently sales of R 20 000. Cash in the bank R9000. There is no sales coming in at the moment.\", \"question_id\": \"intro_business_motivation\", \"response_date\": \"2025-08-29T08:57:55.515Z\"}, {\"value\": \"2024-02-07\", \"question_id\": \"intro_registration_date\", \"response_date\": \"2025-08-29T08:57:55.515Z\"}, {\"value\": \"startup\", \"question_id\": \"intro_business_stage\", \"response_date\": \"2025-08-29T08:57:55.515Z\"}]}', NULL, NULL, NULL, '2025-08-29 10:19:23', '2025-08-29 10:57:55'),
(1942, 'assessment_products_services', 11, '{\"section_id\": \"products_services\", \"is_complete\": false, \"last_updated\": \"2025-08-29T08:26:12.722Z\", \"response_date\": \"2025-08-29T08:26:12.722Z\", \"questionnaire_id\": \"business-assessment-v1\", \"question_responses\": [{\"value\": \"Uniforms for schools, PPE and Scrubs. Customized outfits and bags.\", \"question_id\": \"ps_offerings_list\", \"response_date\": \"2025-08-29T08:26:12.722Z\"}, {\"value\": \"products\", \"question_id\": \"ps_primary_focus\", \"response_date\": \"2025-08-29T08:26:12.722Z\"}, {\"value\": \"Individuals, schools, businesses using PPE, medical practitioners.\", \"question_id\": \"ps_target_market\", \"response_date\": \"2025-08-29T08:26:12.722Z\"}, {\"value\": \"1\", \"question_id\": \"ps_revenue_streams\", \"response_date\": \"2025-08-29T08:26:12.722Z\"}]}', NULL, NULL, NULL, '2025-08-29 10:22:56', '2025-08-29 10:26:12'),
(1943, 'assessment_strategy_cascade', 11, '{\"section_id\": \"strategy_cascade\", \"is_complete\": false, \"last_updated\": \"2025-08-29T08:45:58.698Z\", \"response_date\": \"2025-08-29T08:45:58.698Z\", \"questionnaire_id\": \"business-assessment-v1\", \"question_responses\": [{\"value\": \"I see myself supplying uniforms, PPE locally and sewing for individuals.\", \"question_id\": \"sc_winning_aspiration\", \"response_date\": \"2025-08-29T08:45:58.698Z\"}, {\"value\": \"I want to play locally, be a local supplier within KCD. channels - schools; medical practitioners; corporates and farmers. including the hospitality industry. \", \"question_id\": \"sc_where_play\", \"response_date\": \"2025-08-29T08:45:58.698Z\"}, {\"value\": \"uniqueness - collaboration with other industry players. \", \"question_id\": \"sc_how_win\", \"response_date\": \"2025-08-29T08:45:58.698Z\"}, {\"value\": \"sewing and designing skills and manufacturing skills. management skills, marketing skills and strategies.\", \"question_id\": \"sc_capabilities\", \"response_date\": \"2025-08-29T08:45:58.698Z\"}, {\"value\": \"SACAS - ISO systems - quality control systems: use whiteboard to tracks orders. need a sales and marketing system. accounting systems, HR and payroll systems. Health and Safety systems.\", \"question_id\": \"sc_management_systems\", \"response_date\": \"2025-08-29T08:45:58.698Z\"}]}', NULL, NULL, NULL, '2025-08-29 10:29:12', '2025-08-29 10:45:58'),
