(1996, 'swot_analysis', 26, '{\"external\": {\"threats\": [{\"impact\": \"medium\", \"status\": \"in_progress\", \"category\": \"threat\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:35:39.593Z\", \"assigned_to\": \"Bradley\", \"description\": \"Political situation in the country, businesses are not advertising.\", \"target_date\": \"2025-10-31\", \"action_required\": \"Visit new businesses and educate them on the importance of advertising.\"}, {\"impact\": \"high\", \"status\": \"identified\", \"category\": \"threat\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:37:02.333Z\", \"description\": \"Competitors\", \"action_required\": \"Create uniqueness in your business, (Blue Ocean Theory)\"}], \"opportunities\": [{\"impact\": \"medium\", \"status\": \"planning\", \"category\": \"opportunity\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:33:39.247Z\", \"assigned_to\": \"Bradley\", \"description\": \"Local Municipalities run databases for suppliers.\", \"target_date\": \"2025-10-31\", \"action_required\": \"Ensure you  register on all these databases.\"}, {\"impact\": \"high\", \"status\": \"in_progress\", \"category\": \"opportunity\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:34:51.451Z\", \"assigned_to\": \"Brandley\", \"description\": \"There are loads of new businesses.\", \"target_date\": \"2025-10-31\", \"action_required\": \"Ensure you get to any and all new businesses you can identify.\"}]}, \"internal\": {\"strengths\": [{\"impact\": \"medium\", \"status\": \"in_progress\", \"category\": \"strength\", \"priority\": \"medium\", \"date_added\": \"2025-10-03T09:45:42.454Z\", \"assigned_to\": \"Bradley\", \"description\": \"Qualified Graphic Designer\", \"target_date\": \"2025-10-31\", \"action_required\": \"Need to include this fact in own marketing\"}, {\"impact\": \"medium\", \"status\": \"planning\", \"category\": \"strength\", \"priority\": \"medium\", \"date_added\": \"2025-10-03T09:46:41.619Z\", \"assigned_to\": \"Bradley\", \"description\": \"Experience in the industry\", \"target_date\": \"2025-10-31\", \"action_required\": \"Use experience gained in the past to attract more customers, knowing their pain.\"}, {\"impact\": \"medium\", \"status\": \"planning\", \"category\": \"strength\", \"priority\": \"medium\", \"date_added\": \"2025-10-03T09:47:43.931Z\", \"assigned_to\": \"Bradley\", \"description\": \"Received Digital Printer and Vinal cutter\", \"target_date\": \"2025-10-31\", \"action_required\": \"Develop Sales FAB with this in mind and redesign a brochure for this equipemnt\"}, {\"impact\": \"medium\", \"status\": \"identified\", \"category\": \"strength\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:18:29.150Z\", \"assigned_to\": \"Bradley\", \"description\": \"Office location in Town\", \"target_date\": \"2025-10-31\", \"action_required\": \"Include this benefit to all suppliers.\"}], \"weaknesses\": [{\"impact\": \"high\", \"status\": \"planning\", \"category\": \"weakness\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:21:04.690Z\", \"assigned_to\": \"Bradley\", \"description\": \"Financial Working capital constraints\", \"target_date\": \"2025-12-31\", \"action_required\": \"Develop a business plan with a budget and forecast showing what we will need and how getting that will impact the bottom line.\"}, {\"impact\": \"high\", \"status\": \"identified\", \"category\": \"weakness\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:23:33.593Z\", \"assigned_to\": \"Bradley\", \"description\": \"Implement Financial system.\", \"target_date\": \"2026-01-31\", \"action_required\": \"Investigate an accounting package to implement to generate monthly financial reports.\"}, {\"impact\": \"high\", \"status\": \"planning\", \"category\": \"weakness\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:25:28.884Z\", \"assigned_to\": \"Bradley\", \"description\": \"Weak sales pipeline\", \"target_date\": \"2025-11-30\", \"action_required\": \"Start making client sales calls and introduce a pick 6 system daily. Consider implementing a CRM package.\"}, {\"impact\": \"medium\", \"status\": \"planning\", \"category\": \"weakness\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:27:12.544Z\", \"assigned_to\": \"Bradley\", \"description\": \"Marketing material\", \"target_date\": \"2025-10-31\", \"action_required\": \"Develop marketing materials you can leave behind at customer visits. Ensure you use all your strenghts on the material.\"}, {\"impact\": \"high\", \"status\": \"planning\", \"category\": \"weakness\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:28:27.313Z\", \"assigned_to\": \"Bradley\", \"description\": \"Do not have a sales and marketing Strategy\", \"target_date\": \"2025-10-31\", \"action_required\": \"Develop a sales and marketing strategy identifying what we want to sell to whom?\"}, {\"impact\": \"high\", \"status\": \"planning\", \"category\": \"weakness\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:29:27.159Z\", \"assigned_to\": \"Bradley\", \"description\": \"Do not have the right level of staff.\", \"target_date\": \"2025-10-31\", \"action_required\": \"Start a HR policy file and include your recruitment policy.\"}]}, \"company_id\": \"26\", \"is_complete\": false, \"last_updated\": \"2025-10-13T08:37:50.153Z\", \"analysis_date\": \"2025-10-03T09:45:19.745Z\"}', NULL, NULL, NULL, '2025-10-03 11:45:44', '2025-10-13 10:37:50'),
(1997, 'consolidated_assessment', 26, '{\"metadata\": {\"last_updated\": \"2026-01-14T07:56:29.043Z\", \"current_section\": \"sars_compliance\", \"answered_questions\": 25, \"progress_percentage\": 100}, \"responses\": {\"sc_how_win\": \"by offering quality and innovative offerings to customers, new/unique ideas as a media owner.\", \"sa_strengths\": \"Experience as a graphic designer\", \"sc_where_play\": \"We want to play nationally supplying to business of printing material.\", \"sars_vat_status\": \"compliant\", \"sc_capabilities\": \"Must have sufficient  cash flow. Enough staff to deal with the demand including sales staff.\", \"ps_primary_focus\": \"both\", \"ps_target_market\": \"Businesses that require signage\", \"sa_sales_ability\": 5, \"sars_paye_status\": \"compliant\", \"ps_offerings_list\": \"Any form of signage being signage on buildings, shops or vehicles.\", \"ps_revenue_streams\": 1, \"sars_tax_clearance\": true, \"intro_business_stage\": \"startup\", \"sa_improvement_areas\": \"Finance, we need a bookkeeping systems \\nCRM System we need to be able to track sales activities\\nSales and marketing, we need to identify who we want to sell to and what we want to sell to them.\", \"sa_leadership_skills\": 5, \"sa_marketing_ability\": 5, \"sc_management_systems\": \"HR System, Financial Management System, CRM System. Job card and costing system.\", \"sc_winning_aspiration\": \"Want to be in a position to import signage material and supply to national customers. We want to be a supplier to other printing businesses/signage companies. This include other and more modern signs, billboards window signs and so on.\", \"sars_income_tax_status\": \"compliant\", \"intro_registration_date\": \"2020-12-31\", \"sars_outstanding_issues\": false, \"intro_operating_duration\": \"3_to_5_years\", \"intro_business_motivation\": \"I Started this business because I lost my job during COVID. I was a graphic designer. Started trading December 2020.\", \"intro_business_description\": \"A Fully fledged signage company, doing any form of signage, branding including vehicle branding.\", \"sa_accounting_understanding\": 5}, \"updated_at\": \"2026-01-14T07:56:29.043Z\"}', NULL, NULL, NULL, '2025-10-03 11:56:43', '2026-01-14 09:56:28'),
(1998, 'gps_targets', 26, '{\"finance\": {\"name\": \"Finance Targets\", \"targets\": [{\"status\": \"in_progress\", \"due_date\": \"2025-10-31\", \"evidence\": \"System implemented\", \"priority\": \"high\", \"date_added\": \"2025-10-13T08:47:53.222Z\", \"assigned_to\": \"Bradley\", \"description\": \"Implement an accounting system like Sage in order to get proper monthly reports.\", \"progress_percentage\": 0}, {\"status\": \"not_started\", \"due_date\": \"2025-10-31\", \"evidence\": \"Business plan\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:48:40.577Z\", \"assigned_to\": \"Bradley\", \"description\": \"Create a business plan with proper forecasts and budgets.\", \"progress_percentage\": 0}], \"completion_percentage\": 0}, \"company_id\": \"26\", \"is_complete\": false, \"target_date\": \"2025-10-04T11:27:20.853Z\", \"last_updated\": \"2025-10-13T08:54:23.117Z\", \"sales_marketing\": {\"name\": \"Sales & Marketing Targets\", \"targets\": [{\"status\": \"not_started\", \"due_date\": \"2025-10-31\", \"evidence\": \"Systems report on sales activities\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:46:19.426Z\", \"assigned_to\": \"Bradley\", \"description\": \"Implement the pick 6 system and investigate which CRM system will suite your business.\", \"progress_percentage\": 0}], \"completion_percentage\": 0}, \"strategy_general\": {\"name\": \"Strategy/General Targets\", \"targets\": [{\"status\": \"in_progress\", \"due_date\": \"2025-10-31\", \"evidence\": \"Decide what you are going to sell to whom.\", \"priority\": \"high\", \"date_added\": \"2025-10-04T11:27:26.863Z\", \"assigned_to\": \"Bradley\", \"description\": \"Create a full marketing strategy.\", \"progress_percentage\": 0}, {\"status\": \"not_started\", \"due_date\": \"2025-10-31\", \"evidence\": \"Draft of new marketing material\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:39:15.420Z\", \"description\": \"Create marketing material based on the marketing strategy including your strengths and concerting Features and advantages into benefits.\", \"progress_percentage\": 0}, {\"status\": \"not_started\", \"due_date\": \"2025-10-31\", \"evidence\": \"Completed HR Policy document with the rules and regulations for the business\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:42:44.468Z\", \"description\": \"Start a HR file and focus on recruitment and a work plan for each individual\", \"progress_percentage\": 0}, {\"status\": \"not_started\", \"due_date\": \"2025-10-31\", \"evidence\": \"Engauge with an ISO consulting agency\", \"priority\": \"medium\", \"date_added\": \"2025-10-13T08:44:07.068Z\", \"description\": \"Investigate which ISO standards are applicable and start the process\", \"progress_percentage\": 0}], \"completion_percentage\": 0}, \"personal_development\": {\"name\": \"Personal Development Targets\", \"targets\": [], \"completion_percentage\": 0}}', NULL, NULL, NULL, '2025-10-04 11:27:28', '2025-10-13 10:54:24');
