(2001, 'consolidated_assessment', 14, '{\"metadata\": {\"last_updated\": \"2026-01-15T08:24:22.466Z\", \"current_section\": \"sars_compliance\", \"answered_questions\": 26, \"progress_percentage\": 104}, \"responses\": {\"sc_how_win\": \"My items will be custom made and unique, I will be more active on social media like Tiktok, I also want to look at smaller shops.\", \"sa_strengths\": \"My skills is a strength. \", \"sc_where_play\": \"Smaller towns, Mpumalanga, (cold Areas). Sell to Corporates and Individual .\", \"sars_vat_status\": \"not_applicable\", \"sc_capabilities\": \"Manufacturing skills and experience. Logistics.\", \"ps_primary_focus\": \"products\", \"ps_target_market\": \"Corporates and Individuals. \", \"sa_sales_ability\": 6, \"sars_paye_status\": \"non_compliant\", \"ps_offerings_list\": \"Bags, back packs, clothing and shoes. Corporate gifts.\", \"ps_revenue_streams\": 4, \"sars_tax_clearance\": true, \"intro_business_stage\": \"startup\", \"sa_improvement_areas\": \"Sales and marketing, Finance.\", \"sa_leadership_skills\": 7, \"sa_marketing_ability\": 4, \"sars_compliance_notes\": \"No\", \"sc_management_systems\": \"Quality Control, Financial Management, CRM system, HR System\", \"sc_winning_aspiration\": \"I see a factory made out of shipping containers with three sections one for shoes, one for bags and one for clothing. I see myself finding a number of bigger corporates that will buy from me regularly.\", \"sars_income_tax_status\": \"compliant\", \"intro_registration_date\": \"2017-11-30\", \"sars_outstanding_issues\": false, \"intro_operating_duration\": \"more_than_5_years\", \"intro_business_motivation\": \"Passion for fashion and the creativity. I also identified a GAp in the market in my area. \", \"intro_business_description\": \"A Bag, shoe and clothing manufacturing concern.\", \"sa_accounting_understanding\": 6}, \"updated_at\": \"2026-01-15T08:24:22.466Z\"}', NULL, NULL, NULL, '2026-01-15 10:02:19', '2026-01-15 10:24:22'),
