(2004, 'consolidated_assessment', 5, '{\"metadata\": {\"last_updated\": \"2026-01-23T08:12:24.631Z\", \"current_section\": \"sars_compliance\", \"answered_questions\": 25, \"progress_percentage\": 100}, \"responses\": {\"sc_how_win\": \"I will focus on steam cleaning.\", \"sa_strengths\": \"I have steam cleaning equipment in place.\", \"sc_where_play\": \"Richards Bay, Durban and perhaps outside of Kwazulu Natal.\", \"sars_vat_status\": \"not_applicable\", \"sc_capabilities\": \"Must have steam cleaning equipment, I also need products to support hygiene after steam cleaning.\", \"ps_primary_focus\": \"services\", \"ps_target_market\": \"Individuals, homeowners, car owners truck owners, estate Agents.  Post construction cleaning.\\nFor individuals Bed and Couches. Student accommodation, bed and breakfast & hotels.\", \"sa_sales_ability\": 4, \"sars_paye_status\": \"non_compliant\", \"ps_offerings_list\": \"Cleaning service.\", \"ps_revenue_streams\": 1, \"sars_tax_clearance\": true, \"intro_business_stage\": \"startup\", \"sa_improvement_areas\": \"Marketing and getting more sales.\", \"sa_leadership_skills\": 5, \"sa_marketing_ability\": 4, \"sars_compliance_notes\": \"None\", \"sc_management_systems\": \"Sales and Marketing, quality control, ISO type accreditation.\", \"sc_winning_aspiration\": \"I want a cleaning company with its own cleaning and supplying products based in Richards Bay, Durban and perhaps outside Kwazulu Natal.\", \"sars_income_tax_status\": \"compliant\", \"sars_outstanding_issues\": true, \"intro_operating_duration\": \"1_to_3_years\", \"intro_business_motivation\": \"I want to provide a quality hygienic service to people coming from a rural area where hygiene is a concern.\", \"intro_business_description\": \"My business is a cleaning and steam cleaning, deep cleaning business for homeowners, businesses, car dealerships and estate agents.\", \"sa_accounting_understanding\": 5}, \"updated_at\": \"2026-01-23T08:12:24.631Z\"}', NULL, NULL, NULL, '2026-01-23 09:46:36', '2026-01-23 10:12:23'),
