(2303, 'form_template', NULL, '{\"name\": \"Interview Questions – Enterprise Development Grant Fund\", \"version\": 1, \"sections\": [{\"id\": \"personal_motivation\", \"order\": 1, \"title\": \"Personal Motivation and Vision\", \"questions\": [{\"id\": \"q_about_yourself\", \"type\": \"textarea\", \"label\": \"Briefly tell us about yourself and your business.\", \"children\": [], \"required\": true}, {\"id\": \"q_products_services\", \"type\": \"textarea\", \"label\": \"What products or services does your business offer?\", \"children\": [], \"required\": true}, {\"id\": \"q_inspiration\", \"type\": \"textarea\", \"label\": \"What inspired you to start your business?\", \"children\": [], \"required\": false}, {\"id\": \"q_who_manages\", \"type\": \"text\", \"label\": \"Who manages your business?\", \"children\": [], \"required\": false}, {\"id\": \"q_location\", \"type\": \"textarea\", \"label\": \"Where is your business located? Are you currently renting any premises or do you have a lease agreement with the landlord?\", \"children\": [], \"required\": false}, {\"id\": \"q_five_years\", \"type\": \"textarea\", \"label\": \"Where do you see your company in 5 years?\", \"children\": [], \"required\": false}, {\"id\": \"q_reading\", \"type\": \"text\", \"label\": \"What are you currently reading?\", \"children\": [], \"required\": false}, {\"id\": \"q_social_media\", \"type\": \"textarea\", \"label\": \"What social media and TV programs do you enjoy watching?\", \"children\": [], \"required\": false}]}, {\"id\": \"customer_perspective\", \"order\": 2, \"title\": \"Customer Perspective\", \"questions\": [{\"id\": \"q_customer_problem\", \"type\": \"textarea\", \"label\": \"What customer problem are you solving?\", \"children\": [], \"required\": true}, {\"id\": \"q_target_customers\", \"type\": \"textarea\", \"label\": \"Who are your target customers?\", \"children\": [], \"required\": false}, {\"id\": \"q_reach_customers\", \"type\": \"textarea\", \"label\": \"How do you reach your customers?\", \"children\": [], \"required\": false}, {\"id\": \"q_top_customers\", \"type\": \"text\", \"label\": \"Who are your top 3 paying customers?\", \"children\": [], \"required\": false}]}, {\"id\": \"finance_perspective\", \"order\": 3, \"title\": \"Finance Perspective\", \"questions\": [{\"id\": \"q_revenue_model\", \"type\": \"textarea\", \"label\": \"How does your business make money?\", \"children\": [], \"required\": true}, {\"id\": \"q_monthly_sales\", \"type\": \"text\", \"label\": \"How much sales is your business making per month?\", \"children\": [], \"required\": false}, {\"id\": \"q_customer_debt\", \"type\": \"text\", \"label\": \"How much money do customers owe the business?\", \"children\": [], \"required\": false}, {\"id\": \"q_income_streams\", \"type\": \"textarea\", \"label\": \"What is your primary source of income and what other income streams do you have?\", \"children\": [], \"required\": false}, {\"id\": \"q_investment\", \"type\": \"text\", \"label\": \"How much money have you invested in your business?\", \"children\": [], \"required\": false}, {\"id\": \"q_financial_support\", \"type\": \"boolean\", \"label\": \"Have you received any financial support — loans, grants, etc.?\", \"children\": [{\"id\": \"q_financial_support_details\", \"type\": \"textarea\", \"label\": \"Please provide details of the financial support received.\", \"children\": [], \"required\": false, \"visibleIf\": {\"value\": true}}], \"required\": false}]}, {\"id\": \"risk_decision_making\", \"order\": 4, \"title\": \"Risk-Taking and Decision-Making\", \"questions\": [{\"id\": \"q_current_situation\", \"type\": \"textarea\", \"label\": \"What is the current situation in your business?\", \"children\": [], \"required\": false}, {\"id\": \"q_biggest_challenge\", \"type\": \"textarea\", \"label\": \"What is the greatest challenge your business has faced?\", \"children\": [], \"required\": false}, {\"id\": \"q_overcame_challenge\", \"type\": \"textarea\", \"label\": \"How did you overcome this challenge?\", \"children\": [], \"required\": false}, {\"id\": \"q_innovative_idea\", \"type\": \"textarea\", \"label\": \"What is the most innovative idea you have implemented in your business?\", \"children\": [], \"required\": false}]}, {\"id\": \"governance_esg\", \"order\": 5, \"title\": \"Social Perspectives, Environmental & Governance\", \"questions\": [{\"id\": \"q_has_employees\", \"type\": \"boolean\", \"label\": \"Job creation — do you have employees?\", \"children\": [{\"id\": \"q_employee_count\", \"type\": \"number\", \"label\": \"How many employees do you have?\", \"children\": [], \"required\": false, \"visibleIf\": {\"value\": true}}, {\"id\": \"q_employee_contracts\", \"type\": \"select\", \"label\": \"Do you have employee contracts and provide pay slips?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false, \"visibleIf\": {\"value\": true}}], \"required\": true}, {\"id\": \"q_health_safety\", \"type\": \"select\", \"label\": \"Do you ensure the health and safety of your employees?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}, {\"id\": \"q_registered_wca\", \"type\": \"select\", \"label\": \"Are you registered with WCA / UIF / SARS PAYE?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}, {\"id\": \"q_regulatory_requirements\", \"type\": \"select\", \"label\": \"Are there any regulatory requirements in your sector?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}, {\"id\": \"q_waste\", \"type\": \"select\", \"label\": \"Does your company generate any waste?\", \"options\": [\"Yes\", \"No\", \"N/A\"], \"children\": [], \"required\": false}, {\"id\": \"q_recycling\", \"type\": \"select\", \"label\": \"Do you consider recycling waste generated from your business operations?\", \"options\": [\"Yes\", \"No\", \"N/A\"], \"children\": [], \"required\": false}, {\"id\": \"q_record_keeping\", \"type\": \"select\", \"label\": \"Do you keep records of all your business transactions?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}, {\"id\": \"q_accounting_system\", \"type\": \"select\", \"label\": \"Are you currently using an accounting system?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}, {\"id\": \"q_cipc_returns\", \"type\": \"select\", \"label\": \"Are your CIPC annual returns up to date?\", \"options\": [\"Yes\", \"No\"], \"children\": [], \"required\": false}]}, {\"id\": \"needs_analysis\", \"order\": 6, \"title\": \"Needs Analysis\", \"questions\": [{\"id\": \"q_business_needs\", \"type\": \"textarea\", \"label\": \"What are the three things your business needs to grow?\", \"children\": [], \"required\": false}, {\"id\": \"rifehj7k\", \"type\": \"textarea\", \"label\": \"What opportunities can you identify?\", \"children\": [], \"required\": false}, {\"id\": \"q_extra_jobs\", \"type\": \"number\", \"label\": \"How many extra jobs will this create?\", \"children\": [], \"required\": false}, {\"id\": \"q_sales_increase\", \"type\": \"textarea\", \"label\": \"How much will your sales increase?\", \"children\": [], \"required\": false}, {\"id\": \"94wvhj4i\", \"type\": \"textarea\", \"label\": \"What areas do you identify as your key weaknesses?\", \"children\": [], \"required\": false}, {\"id\": \"9q80gcy4\", \"type\": \"textarea\", \"label\": \"What are your primary strengths?\", \"children\": [], \"required\": false}, {\"id\": \"23po5r6g\", \"type\": \"textarea\", \"label\": \"What key threats could impact your success?\", \"children\": [], \"required\": false}]}, {\"id\": \"vpu1b8vv\", \"order\": 7, \"title\": \"Additional Info & Notes\", \"questions\": [{\"id\": \"l6z3wqin\", \"type\": \"textarea\", \"label\": \"Do you have any other information that you would like to share?\", \"children\": [], \"required\": false}, {\"id\": \"af0z459l\", \"type\": \"textarea\", \"label\": \"Additional Notes\", \"children\": [], \"required\": false}]}], \"description\": \"Standard interview questionnaire covering personal motivation, customer perspective, finance, risk-taking, governance (ESG) and needs analysis.\"}', NULL, NULL, NULL, '2026-05-04 05:56:13', '2026-05-04 10:40:32'),
