(2311, 'form_template', NULL, '{\"meta\": {\"decision\": {\"field\": \"recommendation\", \"options\": [\"Proceed\", \"Hold\", \"Decline\"]}, \"notes_enabled\": true}, \"name\": \"Pitch Workshop Evaluation\", \"version\": 1, \"sections\": [{\"id\": \"presentation\", \"order\": 1, \"title\": \"Presentation Assessment\", \"questions\": [{\"id\": \"problem_clarity\", \"type\": \"rating\", \"label\": \"Clarity of problem being solved\", \"scale\": 5, \"required\": false}, {\"id\": \"solution_clarity\", \"type\": \"rating\", \"label\": \"Clarity of solution\", \"scale\": 5, \"required\": false}, {\"id\": \"value_proposition\", \"type\": \"rating\", \"label\": \"Strength of value proposition\", \"scale\": 5, \"required\": false}]}, {\"id\": \"business_model\", \"order\": 2, \"title\": \"Business Model\", \"questions\": [{\"id\": \"revenue_model_clear\", \"type\": \"boolean\", \"label\": \"Revenue model is clear and realistic\", \"required\": true}, {\"id\": \"pricing_viable\", \"type\": \"boolean\", \"label\": \"Pricing strategy is viable\", \"required\": true}]}, {\"id\": \"founder\", \"order\": 3, \"title\": \"Founder Capability\", \"questions\": [{\"id\": \"founder_confidence\", \"type\": \"rating\", \"label\": \"Founder confidence and communication\", \"scale\": 5, \"required\": false}, {\"id\": \"execution_ability\", \"type\": \"rating\", \"label\": \"Ability to execute\", \"scale\": 5, \"required\": false}]}, {\"id\": \"readiness\", \"order\": 4, \"title\": \"Business Readiness\", \"questions\": [{\"id\": \"traction_present\", \"type\": \"boolean\", \"label\": \"Business shows traction\", \"required\": true}, {\"id\": \"scalable\", \"type\": \"boolean\", \"label\": \"Business is scalable\", \"required\": true}]}], \"description\": \"Assess clarity, readiness and execution potential after the first pitch. 4 sections · Presentation, Business Model, Founder Capability, Readiness · rating scales + boolean checks + recommendation decision.\"}', NULL, NULL, NULL, '2026-05-05 12:40:53', '2026-05-05 12:40:55'),
(2312, 'form_template', NULL, '{\"meta\": {\"decision\": {\"field\": \"final_decision\", \"options\": [\"Approve\", \"Decline\", \"Defer\"]}, \"notes_enabled\": true}, \"name\": \"Panel Pitch Evaluation\", \"version\": 1, \"sections\": [{\"id\": \"4qcjo49v\", \"order\": 1, \"title\": \"Judging Panel\", \"questions\": [{\"id\": \"ng9oxjom\", \"type\": \"select\", \"label\": \"Judge Name\", \"options\": [\"N Naido\", \"M Wilkea\", \"C Buthelezi\"], \"children\": [], \"required\": false}]}, {\"id\": \"business_strength\", \"order\": 2, \"title\": \"Business Strength\", \"questions\": [{\"id\": \"market_demand\", \"type\": \"text\", \"label\": \"Market demand is strong\", \"scale\": 5, \"children\": [], \"required\": false}, {\"id\": \"competitive_advantage\", \"type\": \"rating\", \"label\": \"Has a clear competitive advantage\", \"scale\": 5, \"required\": false}]}, {\"id\": \"financial_viability\", \"order\": 3, \"title\": \"Financial Viability\", \"questions\": [{\"id\": \"revenue_potential\", \"type\": \"rating\", \"label\": \"Revenue growth potential\", \"scale\": 5, \"required\": false}, {\"id\": \"cost_structure\", \"type\": \"boolean\", \"label\": \"Cost structure is sustainable\", \"required\": true}]}, {\"id\": \"impact\", \"order\": 4, \"title\": \"Impact Assessment\", \"questions\": [{\"id\": \"job_creation\", \"type\": \"rating\", \"label\": \"Job creation potential\", \"scale\": 5, \"required\": false}, {\"id\": \"community_impact\", \"type\": \"rating\", \"label\": \"Community impact\", \"scale\": 5, \"required\": false}]}, {\"id\": \"risk\", \"order\": 5, \"title\": \"Risk Evaluation\", \"questions\": [{\"id\": \"operational_risk\", \"type\": \"select\", \"label\": \"Operational risk level\", \"options\": [\"Low\", \"Medium\", \"High\"], \"required\": true}, {\"id\": \"financial_risk\", \"type\": \"select\", \"label\": \"Financial risk level\", \"options\": [\"Low\", \"Medium\", \"High\"], \"required\": true}]}], \"description\": \"Final evaluation before approval — higher scrutiny, structured scoring. 4 sections · Business Strength, Financial Viability, Impact, Risk · rating scales, select risk levels + final decision.\"}', NULL, NULL, NULL, '2026-05-05 12:41:01', '2026-05-06 07:42:57'),
