(2627, 'form_template', NULL, '{\"meta\": {\"decision\": {\"field\": \"final_decision\", \"options\": [\"Approve\", \"Decline\", \"Defer\"]}, \"multi_judge\": true, \"notes_enabled\": true}, \"name\": \"Stage 3 — Investment Pitch Judge Evaluation\", \"version\": 1, \"sections\": [{\"id\": \"panel_setup\", \"order\": 1, \"title\": \"Panel Setup\", \"questions\": [{\"id\": \"presenting_company\", \"type\": \"applicant_picker\", \"label\": \"Presenting Company\", \"required\": true, \"pickerConfig\": {\"stages\": [\"stage_1777885810811\"], \"placeholder\": \"Search companies...\", \"allowFreeText\": false}}, {\"id\": \"judge_name\", \"type\": \"user_picker\", \"label\": \"Judge Name\", \"required\": true, \"pickerConfig\": {\"roles\": [\"System Administrator\", \"Coordinator\", \"Judge\", \"External Judge\"], \"placeholder\": \"Search judges...\", \"allowFreeText\": false}}, {\"id\": \"pitch_date\", \"type\": \"date\", \"label\": \"Pitch Date\", \"required\": true}, {\"id\": \"time_slot\", \"type\": \"text\", \"label\": \"Time Slot (e.g. 10:15 – 10:30)\", \"required\": false}, {\"id\": \"check_in\", \"type\": \"boolean\", \"label\": \"Presenter checked in?\", \"required\": true}]}, {\"id\": \"investment_criteria\", \"order\": 2, \"title\": \"Investment Criteria (9 × 1–5)\", \"questions\": [{\"id\": \"c1_business_background\", \"type\": \"rating\", \"label\": \"1. Business Background — How much sense does this business make?\", \"scale\": 5, \"required\": true}, {\"id\": \"c1_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c2_location\", \"type\": \"rating\", \"label\": \"2. Location (S32 requirement) — Where are you currently operating from? (Lease or own)\", \"scale\": 5, \"required\": true}, {\"id\": \"c2_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c3_problem\", \"type\": \"rating\", \"label\": \"3. Problem or Need — The problem is real; potential customers have significant pain or large unfulfilled needs.\", \"scale\": 5, \"required\": true}, {\"id\": \"c3_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c4_solution\", \"type\": \"rating\", \"label\": \"4. Solution — How will the company address the identified problem or need?\", \"scale\": 5, \"required\": true}, {\"id\": \"c4_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c5_current_situation\", \"type\": \"rating\", \"label\": \"5. Current Situation — What is the current situation in the business?\", \"scale\": 5, \"required\": true}, {\"id\": \"c5_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c6_business_needs\", \"type\": \"rating\", \"label\": \"6. Business Needs — How will this investment solve the current situation?\", \"scale\": 5, \"required\": true}, {\"id\": \"c6_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c7_investment_plan\", \"type\": \"rating\", \"label\": \"7. Investment Plan — Is the plan reasonable given the stage and size of the business?\", \"scale\": 5, \"required\": true}, {\"id\": \"c7_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c8_roi\", \"type\": \"rating\", \"label\": \"8. Return on Investment — Growth Potential: What are the future plans?\", \"scale\": 5, \"required\": true}, {\"id\": \"c8_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}, {\"id\": \"c9_presentation\", \"type\": \"rating\", \"label\": \"9. Overall Presentation & Q&A — Clear, convincing, engaging, passionate, handled Q&A effectively, knows facts and numbers, honest, likeable.\", \"scale\": 5, \"required\": true}, {\"id\": \"c9_notes\", \"type\": \"textarea\", \"label\": \"Comments / Notes\", \"required\": false}]}], \"description\": \"Official judge evaluation sheet used at Stage 3 investment pitches. 9 criteria scored 1–5 each (min 9 · avg 27 · max 45) · per-criterion notes · panel setup with judge names · Approve / Decline / Defer decision.\", \"built_in_key\": \"stage3_investment_pitch_judge_v1\"}', NULL, NULL, NULL, '2026-05-07 18:48:04', '2026-05-11 11:01:33'),
