(2712, 'form_submission', 2375, '{\"meta\": {\"interviewer_notes\": \"\"}, \"status\": \"submitted\", \"answers\": {\"q_waste\": \"N/A\", \"23po5r6g\": \"People think they can do our service all by themselves only to discover afterwards they can not deal with it.\", \"94wvhj4i\": \"Staffing, we do not have the correct people in place, people who are committed. \", \"9q80gcy4\": \"Very strong training and experience in business, I am able to share .\", \"l6z3wqin\": \"No\", \"q_reading\": \"Home of machines (A Book)\", \"q_location\": \"I have a lease I am renting in Wildandweide.\", \"q_recycling\": \"N/A\", \"q_extra_jobs\": 1, \"q_five_years\": \"I see my business more on a subscription base, I want to be able to delegate work to the correct professional.\", \"q_investment\": \"I invested about R200 000 into this business\", \"q_inspiration\": \"As a business coach I identified that startups and even small business struggle with compliance.\", \"q_who_manages\": \"I mange my business with the support of two other professionals in labour. Also supported by other professionals\", \"q_cipc_returns\": \"Yes\", \"q_social_media\": \"Facebook, do not watch TV\", \"q_customer_debt\": \"Nothing\", \"q_has_employees\": true, \"q_health_safety\": \"No\", \"q_monthly_sales\": \"R105 000 per month\", \"q_revenue_model\": \"I have three models for charging, I ask for a retainer. I charge for work done depending on work done. When I use other professional I mark up the charge.\", \"q_top_customers\": \"Malandala Construction, Nomuntu Projects, Sata South African Technicials Association.\", \"q_about_yourself\": \"My business focus on compliance in business. We take care of deadlines for Entrepreneurs who need to apply for work. I Am a business coach and consultant and compliance is what I notice to be a problem,\", \"q_business_needs\": \"1 Software in terms of something to control all the different apps we are using, 2 we need hardware for graphic designs.\", \"q_employee_count\": 2, \"q_income_streams\": \"Consulting, (Retainers) I also co facilitate some training.\", \"q_record_keeping\": \"Yes\", \"q_registered_wca\": \"No\", \"q_sales_increase\": \"Sales will increase by about 30%\", \"q_innovative_idea\": \"Now that we know what customers really need we can start customizing our service/platform.\", \"q_reach_customers\": \"I advertise on Snapit (Marketing portal) I do presentations at Forums, Chambers and other networking events\", \"q_customer_problem\": \"Customer have compliance issues which stops them from getting work. I solve that for them.\", \"q_target_customers\": \"Entrepreneurs and small businesses.\", \"q_accounting_system\": \"Yes\", \"q_biggest_challenge\": \"No being able to expose / position my business in the past was a huge challenge.\", \"q_current_situation\": \"I am managing the business with my two other professional. There is a healthy pipeline of businesses looking for our services. Right now we are looking for more professionals to join.\", \"q_financial_support\": false, \"q_products_services\": \"We start for company registrations, to amendments keeping the registrations up to date, together with all other compliance requirements. \", \"q_employee_contracts\": \"Yes\", \"q_overcame_challenge\": \"We had to sit and look back at who our customers were and ask ourselves the questions (Market Research) if people really want this type of service. \", \"q_regulatory_requirements\": \"Yes\"}, \"submitted_at\": \"2026-05-11T11:40:08.551Z\", \"applicant_label\": \"Unplugged Concepts\", \"form_template_id\": 2303, \"form_template_name\": \"Interview Questions – Enterprise Development Grant Fund\"}', 2303, NULL, NULL, '2026-05-11 13:40:10', '2026-05-11 13:40:10'),
