(2714, 'form_submission', 2092, '{\"meta\": {\"interviewer_notes\": \"\"}, \"status\": \"submitted\", \"answers\": {\"q_waste\": \"Yes\", \"23po5r6g\": \"Having to take shortcuts, competition.\", \"94wvhj4i\": \"The Financial Side\", \"9q80gcy4\": \"Marketing\", \"l6z3wqin\": \"I also did a program with Black Umbrella\", \"q_reading\": \"Nothing specific, did a course lately Finance for non financial people\", \"q_location\": \"Esikhaweni, working from home.\", \"q_recycling\": \"Yes\", \"q_extra_jobs\": 5, \"q_five_years\": \"I see myself owning a wedding and conference center with different branches employing more people.\", \"q_investment\": \"R300 000 to R400 000\", \"q_inspiration\": \"I saw that I have potential and Iove this type of business, I also create jobs for people.\", \"q_who_manages\": \"I manage the business\", \"q_cipc_returns\": \"Yes\", \"q_social_media\": \"I use social media platforms; this is where I advertise my work.\", \"q_customer_debt\": \"No\", \"q_has_employees\": true, \"q_health_safety\": \"Yes\", \"q_monthly_sales\": \"R50 000 to R60 000\", \"q_revenue_model\": \"Decor makes the most money for me. I believe dry hire will make money in the future.\", \"q_top_customers\": \"Mondi (1job), Individuals for Esikhaweni and then my Durban customers for white weddings.\", \"q_about_yourself\": \"I am pubic Relations Graduate, I own this business, we do events corporate to individual events. We also do Florist type of work, specializing in decor.\", \"q_business_needs\": \"1 I need mentorship regarding the financial side of the business. 2 Equipment chairs and tables. 3 Tents\", \"q_employee_count\": 5, \"q_income_streams\": \"Decor.\", \"q_record_keeping\": \"Yes\", \"q_registered_wca\": \"Yes\", \"q_sales_increase\": \"30%\", \"q_innovative_idea\": \"The events that I host myself where we look for sponsors to the event.\", \"q_reach_customers\": \"Social Media platforms like facebook \", \"q_customer_problem\": \"We make sure our customers do to have the stress of planning and executing events.\", \"q_target_customers\": \"Corporates, Individuals, companies , churches. \", \"q_accounting_system\": \"No\", \"q_biggest_challenge\": \"We do not always have what the customer wants, often we have to drive to Durban to hire what the customers want.\", \"q_current_situation\": \"Currently we are experiencing a dry season. It is the time of year. We are doing floral arrangements at this time.\", \"q_financial_support\": true, \"q_products_services\": \"Event Management, decor, Catering Flower arrangements.\", \"q_employee_contracts\": \"Yes\", \"q_overcame_challenge\": \"I bought a bakkie for the business so that I can drive to Durban to fetch what I need and not rely of delivery.\", \"q_financial_support_details\": \"NDY - R50 000 (2023)\"}, \"submitted_at\": \"2026-05-11T12:06:44.684Z\", \"applicant_label\": \"Khosievents\", \"form_template_id\": 2303, \"form_template_name\": \"Interview Questions – Enterprise Development Grant Fund\"}', 2303, NULL, NULL, '2026-05-11 14:06:46', '2026-05-11 14:06:46'),
