(2716, 'form_submission', 2211, '{\"meta\": {\"interviewer_notes\": \"\"}, \"status\": \"submitted\", \"answers\": {\"q_waste\": \"Yes\", \"23po5r6g\": \"I am in debt at the moment paying back loans.\", \"94wvhj4i\": \"Do not have stock Working capital.\", \"9q80gcy4\": \"I am educated in business management\", \"q_location\": \"Ginginlovu, renting space from the mall.\", \"q_extra_jobs\": 5, \"q_five_years\": \"I see myself franching this business, seeing myself as the person at the top of the business working on the business not working in the business\", \"q_investment\": \"Do not know.\", \"q_inspiration\": \"I have 23 years of experience in this type of business.\", \"q_who_manages\": \"I manage the business. \", \"q_cipc_returns\": \"Yes\", \"q_has_employees\": true, \"q_revenue_model\": \"I sell food.\", \"q_top_customers\": \"Individuals, SAPS, Traffic Department.\", \"q_about_yourself\": \"The business is a restaurant selling food in my community. Started the business in 2003, in the umlalazi area based in Ginginlovu. it is at the hopping center\", \"q_business_needs\": \"I am asking for assistance to buy stock.  I also need marketing equipment.\", \"q_employee_count\": 3, \"q_record_keeping\": \"Yes\", \"q_registered_wca\": \"Yes\", \"q_sales_increase\": \"My sales will go up by 60%\", \"q_reach_customers\": \"People who visit the mall find me there.\", \"q_customer_problem\": \" Chicken fish meat all on one platter. I give combo meals.\", \"q_target_customers\": \"People in the area\", \"q_accounting_system\": \"No\", \"q_financial_support\": true, \"q_products_services\": \"Selling food to local market, ie individuals. schools, business.\", \"q_employee_contracts\": \"Yes\", \"q_regulatory_requirements\": \"Yes\", \"q_financial_support_details\": \"Sedfa sponsored me with the equipment I need.\"}, \"submitted_at\": \"2026-05-11T12:25:23.053Z\", \"applicant_label\": \"Nzuza Lifestyle\", \"form_template_id\": 2303, \"form_template_name\": \"Interview Questions – Enterprise Development Grant Fund\"}', 2303, NULL, NULL, '2026-05-11 14:25:24', '2026-05-11 14:25:24'),
