(2718, 'form_submission', 2115, '{\"meta\": {\"interviewer_notes\": \"\"}, \"status\": \"draft\", \"answers\": {\"23po5r6g\": \"Not advertising my business because I do not have money.\", \"94wvhj4i\": \"Not having turnover  cashflow.\", \"9q80gcy4\": \"I can sell.\", \"rifehj7k\": \"opportunity to pick up cargo clients at the harbour.\", \"q_reading\": \"Bible and maagazines\", \"q_extra_jobs\": 3, \"q_five_years\": \"I see myself managing a big agency helping other people in the business.\", \"q_investment\": \"R350 000\", \"q_inspiration\": \"Haminah is my grandmothers name. She was my biggest support, after University I could not find work so I started this business. I studies tourism at Uni and added supply chain management.\", \"q_who_manages\": \"I manage my own business.\", \"q_cipc_returns\": \"Yes\", \"q_social_media\": \"Dont watch tv but listen to radio,\", \"q_customer_debt\": \"R6 000 for individuals\", \"q_has_employees\": false, \"q_health_safety\": \"No\", \"q_monthly_sales\": \"Last year I made about R200 000 profit for the year.\", \"q_revenue_model\": \"I make money on solo bookings for individuals, short stay like two nights only. But I also make a lot of money with school bookings.\", \"q_top_customers\": \"\", \"q_about_yourself\": \"I am a cofounder of this business. its a travel agency, I am a qualified tour guide, we are doing tours at the harbor. We also do educational tours for schools. \", \"q_business_needs\": \"bakkie, copy machine, laptop\", \"q_income_streams\": \"Bookings, Solo, School and Corporate business, I also sell clothes on the side line.\", \"q_record_keeping\": \"Yes\", \"q_sales_increase\": \"25%\\n\", \"q_innovative_idea\": \"implemented GDS R6590. invested to improve invoicing and bookings and designing iternaries.\", \"q_reach_customers\": \"I use a website. \", \"q_customer_problem\": \"all travel related services \", \"q_target_customers\": \"Corporate business, Individuals, Government and schools.\", \"q_accounting_system\": \"Yes\", \"q_biggest_challenge\": \"Not having cash in the business (cash Flow)\", \"q_current_situation\": \"We are going business to business looking for a partner. We are looking for tenders from Government.\", \"q_financial_support\": false, \"q_products_services\": \"Tours from the harbor also do booking for accommodation at Hluhluwe. \", \"q_overcame_challenge\": \"I look for investors for what I need and do a JV per transaction.\", \"q_regulatory_requirements\": \"Yes\"}, \"submitted_at\": \"2026-05-11T12:58:06.177Z\", \"applicant_label\": \"Haminah\", \"form_template_id\": 2303, \"form_template_name\": \"Interview Questions – Enterprise Development Grant Fund\"}', 2303, NULL, NULL, '2026-05-11 14:58:04', '2026-05-11 14:58:07'),
